const body = $input.first().json;

const userName = body.data?.user_name || 'Artist';
const userEmail = body.data?.user_email;
const eventType = body.event_type || 'lesson.completed';
const completed = body.data?.total_completed_lessons || 0;
const score = body.data?.score;
const skillLevel = body.data?.skill_level || 'beginner';
const isMilestone = eventType === 'progress.milestone';

if (!userEmail) {
  throw new Error('No user_email in event data');
}

let emailSubject, emailBody;

if (isMilestone) {
  emailSubject = `🏆 Milestone reached! ${completed} lessons completed, ${userName}!`;
  emailBody = `Hi ${userName},

Amazing work! You've just reached a milestone — ${completed} lessons completed!

You're making incredible progress on your art journey. Keep pushing forward!

Skill level: ${skillLevel}
${score !== undefined && score !== null ? `Last score: ${score}%` : ''}

Continue your journey: https://art-buddy-frontend.onrender.com

The Art Buddy Team`;
} else {
  emailSubject = `✅ Great job completing your lesson, ${userName}!`;
  emailBody = `Hi ${userName},

You just completed a lesson — nice work!

Total lessons completed: ${completed}
Skill level: ${skillLevel}
${score !== undefined && score !== null ? `Score: ${score}%` : ''}

Ready for your next lesson? https://art-buddy-frontend.onrender.com

Keep creating!
The Art Buddy Team`;
}

return [{
  json: {
    user_email: userEmail,
    user_name: userName,
    emailSubject,
    emailBody
  }
}];
